import { LetItGo } from '../../src';

const { DEFAULT_OPTIONS } = LetItGo;

document.addEventListener('DOMContentLoaded', () => {
  const snow = new LetItGo({ root: document.getElementById('root') });

  const switchInput = document.querySelector<HTMLInputElement>('#is-snow');
  switchInput.checked = true;
  switchInput.addEventListener('change', ({ target }) => {
    const switchLabel = document.querySelector('[for="is-snow"]');

    if ((target as HTMLInputElement).checked) {
      snow.letItGoAgain();
      switchLabel.textContent = 'Let It Stop!';
      return;
    }

    snow.letItStop();
    switchLabel.textContent = 'Let It Go!';
  });

  const numberInput = document.querySelector<HTMLInputElement>('#number');
  numberInput.value = `${DEFAULT_OPTIONS.number}`;
  numberInput.addEventListener('input', ({ target }) => {
    snow.number = +(target as HTMLInputElement).value;
  });

  const colorInput = document.querySelector<HTMLInputElement>('#color');
  colorInput.value = DEFAULT_OPTIONS.color;
  colorInput.addEventListener('input', ({ target }) => {
    snow.color = (target as HTMLInputElement).value;
  });

  let [x1, x2] = DEFAULT_OPTIONS.velocityXRange;
  const updateXLabelContent = () => {
    const xLabel = document.querySelector<HTMLLabelElement>('#x-range');
    xLabel.textContent = xLabel.textContent.replace(/\(.*\)/, `(${[x1, x2].sort().join(' to ')})`);
  };

  updateXLabelContent();

  const x1Input = document.querySelector<HTMLInputElement>('#x-range-value-1');
  x1Input.value = `${x1}`;
  x1Input.addEventListener('change', ({ target }) => {
    const { value } = target as HTMLInputElement;
    x1 = +value;
    snow.velocityXRange = [x1, x2];

    updateXLabelContent();
  });

  const x2Input = document.querySelector<HTMLInputElement>('#x-range-value-2');
  x2Input.value = `${x2}`;
  x2Input.addEventListener('change', ({ target }) => {
    const { value } = target as HTMLInputElement;
    x2 = +value;
    snow.velocityXRange = [x1, x2];

    updateXLabelContent();
  });

  // const [y1, y2] = DEFAULT_OPTIONS.velocityYRange;
  // const y1Input = document.querySelector<HTMLInputElement>('#y-range-value-1');
  // y1Input.value = `${y1}`;
  // y1Input.addEventListener('change', ({ target }) => {
  //   const { value } = target as HTMLInputElement;
  //   y1 = +value;
  //   snow.velocityXRange = [y1, y2];

  //   updateXLabelContent();
  // });

  // const y2Input = document.querySelector<HTMLInputElement>('#y-range-value-2');
  // y2Input.value = `${y2}`;
  // y2Input.addEventListener('change', ({ target }) => {
  //   const { value } = target as HTMLInputElement;
  //   y2 = +value;
  //   snow.velocityXRange = [y1, y2];

  //   updateXLabelContent();
  // });
});
